import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);

  useEffect(() => {
    // Backend मधून डेटा मिळवणे
    const getRequests = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/requests');
        setRequests(res.data);
      } catch (err) {
        console.error("Fetch error:", err);
      }
    };
    getRequests();
  }, []);

  return (
    <div className="container py-5">
      <h2 className="text-center fw-bold mb-4">Admin Dashboard - Project Requests</h2>
      <div className="table-responsive shadow rounded p-3 bg-white">
        <table className="table table-hover border">
          <thead className="table-primary text-dark">
            <tr>
              <th>Date</th>
              <th>Client Name</th>
              <th>Email</th>
              <th>Service</th>
              <th>Details</th>
            </tr>
          </thead>
          <tbody>
            {requests.map((req) => (
              <tr key={req._id}>
                <td>{new Date(req.date).toLocaleDateString()}</td>
                <td className="fw-bold">{req.fullName}</td>
                <td>{req.email}</td>
                <td><span className="badge bg-info text-dark">{req.serviceType}</span></td>
                <td>{req.projectDetails}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
